Berikut implementasi `PrimeIterator` menggunakan Python. Kelas ini mengimplementasikan protokol iterator standar (`__iter__` dan `__next__`).

### Implementasi Kelas

```python
import math

class PrimeIterator:
    def __init__(self, start=2):
        self.current = start if start % 2 != 0 else start + 1
        if start <= 2:
            self.current = 2
            self._passed_two = False
        else:
            self._passed_two = True

    def __iter__(self):
        return self

    def __next__(self):
        if self.current == 2 and not self._passed_two:
            self._passed_two = True
            return 2

        while True:
            if self._is_prime(self.current):
                result = self.current
                self.current += 2  # Skip even numbers
                return result
            self.current += 2

    def _is_prime(self, n):
        if n < 2:
            return False
        if n == 2:
            return True
        if n % 2 == 0:
            return False

        limit = int(math.sqrt(n)) + 1
        for i in range(3, limit, 2):
            if n % i == 0:
                return False
        return True

# Usage Example
# primes = PrimeIterator()
